package com.hospital.management.model;import java.time.*;import java.util.Objects;
/** Doctor availability window used by administration and future appointment booking. */
public class DoctorSchedule{private Long scheduleId,doctorId,departmentId;private String doctorName,departmentName,dayOfWeek;private LocalTime startTime,endTime;private int slotDurationMinutes;private boolean available;private LocalDateTime createdAt,updatedAt;public Long getScheduleId(){return scheduleId;}public void setScheduleId(Long v){scheduleId=v;}public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public String getDoctorName(){return doctorName;}public void setDoctorName(String v){doctorName=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getDepartmentName(){return departmentName;}public void setDepartmentName(String v){departmentName=v;}public String getDayOfWeek(){return dayOfWeek;}public void setDayOfWeek(String v){dayOfWeek=v;}public LocalTime getStartTime(){return startTime;}public void setStartTime(LocalTime v){startTime=v;}public LocalTime getEndTime(){return endTime;}public void setEndTime(LocalTime v){endTime=v;}public int getSlotDurationMinutes(){return slotDurationMinutes;}public void setSlotDurationMinutes(int v){slotDurationMinutes=v;}public boolean isAvailable(){return available;}public void setAvailable(boolean v){available=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}public boolean equals(Object o){return this==o||(o instanceof DoctorSchedule s&&scheduleId!=null&&scheduleId.equals(s.scheduleId));}public int hashCode(){return Objects.hashCode(scheduleId);}public String toString(){return"DoctorSchedule{id="+scheduleId+", doctorId="+doctorId+", day="+dayOfWeek+", start="+startTime+"}";}}
